import{f as a,ab as t,p as i,t as r}from"./chunks/framework.A6r4HTKL.js";const u=JSON.parse('{"title":"Tape Backup","description":"This page gives information about how tape backup works using LTO tapes as a medium.","frontmatter":{"title":"Tape Backup","category":"Data","outline":1,"description":"This page gives information about how tape backup works using LTO tapes as a medium."},"headers":[],"relativePath":"administer-science/data/tape-backup/index.md","filePath":"administer-science/data/tape-backup/index.md"}'),o={name:"administer-science/data/tape-backup/index.md"};function s(n,e,c,p,d,l){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="what-is-tape-backup" tabindex="-1">What is tape backup <a class="header-anchor" href="#what-is-tape-backup" aria-label="Permalink to &quot;What is tape backup&quot;">​</a></h1><p>Our tape service uses the LTO (Linear Tape-Open) format optimised for high capacity and storage density. LTO tapes provide a reliable way to store your data offline for maximum protection against malicious attacks such as ransomware. The tape service can also be used as a cost-effective way to maintain a backup of your lab data.</p><h2 id="what-is-lto-tape" tabindex="-1">What is LTO tape <a class="header-anchor" href="#what-is-lto-tape" aria-label="Permalink to &quot;What is LTO tape&quot;">​</a></h2><p>LTO is a magnetic tape storage technology widely used for backup, archiving, and data transfer. As an open standard, LTO is not controlled by a single manufacturer, which promotes compatibility and innovation across the industry. Known for its reliability, capacity, and cost-effectiveness, LTO tapes are designed to store vast amounts of data securely over extended periods.</p><h2 id="reliability" tabindex="-1">Reliability <a class="header-anchor" href="#reliability" aria-label="Permalink to &quot;Reliability&quot;">​</a></h2><p>One of the standout features of LTO tapes is their exceptionally low error rate. With a bit error rate of just 1 error in 10^19 bits, LTO tapes are approximately 10,000 times more reliable than hard disks and 1,000 times more reliable than SSDs. This reliability is achieved through advanced error correction code (ECC) technology, which ensures data is written accurately and any errors are promptly detected and corrected. This makes LTO tapes an ideal choice for backup and archival purposes where maintaining data integrity over long periods is essential.</p><h2 id="security-features" tabindex="-1">Security features <a class="header-anchor" href="#security-features" aria-label="Permalink to &quot;Security features&quot;">​</a></h2><p>LTO tapes are an excellent choice for storing sensitive data. One key feature is the ability to encrypt data on-the-fly, providing a strong defence against unauthorised access. Additionally, LTO tapes can be configured in a WORM (Write Once, Read Many) format, which prevents data from being altered or deleted once written. Another security aspect LTO tape offers is ability to store your data offline in a secure location. This way even if system and data is compromised, your data stays safe, inaccessible from the internet.</p><h2 id="tape-archive-vs-tape-backup" tabindex="-1">Tape archive vs tape backup <a class="header-anchor" href="#tape-archive-vs-tape-backup" aria-label="Permalink to &quot;Tape archive vs tape backup&quot;">​</a></h2><p><strong>Tape archive</strong></p><p>A tape archive is a long-term storage solution for data that is no longer in regular use or data that requires extra safety measures to store. Archived data is typically stored offline for up to 10 years. Archive jobs are run in &quot;Copy&quot; mode, meaning your data is written to two separate tapes to ensure recoverability. After a successful write, archive tapes are removed from the tape library and stored offline in a secure location. Depending on dataset size, recovery may take additional time since the tapes need to be returned to the library manually.</p><p><strong>Tape backup</strong></p><p>Unlike tape archive, regular tape backup is designed to minimise costs while maintaining a high level of data integrity and security. Tape backups run automatically on a predetermined schedule and are retained for a predefined period. Recovery is usually much faster than with tape archive, although several factors can affect the recovery timeline.</p><h2 id="recovery-from-tape" tabindex="-1">Recovery from tape <a class="header-anchor" href="#recovery-from-tape" aria-label="Permalink to &quot;Recovery from tape&quot;">​</a></h2><p>Recovery differs between tape archive and tape backup.</p><p>In most cases, individual files can be recovered from a tape backup quickly. This is not always the case with a tape archive. If you need to recover a file within one year of the archive job, file-level recovery is possible. After one year, which is the most common scenario for archived data, a full job recovery is required. This is due to measures we take to manage the size of our backup catalog, which would otherwise grow indefinitely.</p><h2 id="tape-backup-software" tabindex="-1">Tape backup software <a class="header-anchor" href="#tape-backup-software" aria-label="Permalink to &quot;Tape backup software&quot;">​</a></h2><p>We are using bacula community edition which is an open source sofware that has been around and actively developed since January 2000. This sofware allows us to scale our tape service efficiently, reduce costs and maintain high level of data integrity and security.</p><p>You can read more on bacula <a href="https://en.wikipedia.org/wiki/Bacula" target="_blank" rel="noreferrer">here</a>. Official documentation of bacula can be found <a href="https://docs.baculasystems.com/index.html" target="_blank" rel="noreferrer">here</a></p><h2 id="how-can-i-get-my-data-on-tape" tabindex="-1">How can I get my data on tape? <a class="header-anchor" href="#how-can-i-get-my-data-on-tape" aria-label="Permalink to &quot;How can I get my data on tape?&quot;">​</a></h2><p>You can start by visiting our <a href="/administer-science/service-desk/lab-orders#tape-backup">service desk</a>.</p>',21)])])}const f=a(o,[["render",s]]);export{u as __pageData,f as default};
